import {InuFormsUtils} from 'inugami-ng/utils'

interface UserForm {
  uid: string;
  firstName: string;
  lastName: string;
  email: string;
  old: number;
}

@Component({
             templateUrl: './inu-input-text.view.html',
             styleUrls  : ['./inu-input-text.view.scss'],
             imports    : [
               InuCode,
               InuInputText,
               InuCode,
               InuTableFlex,
               InuTableFlexHeader,
               InuTableFlexRow,
               InuTableFlexCell,
               InuPanelTabs,
               InuPanelTab,
               FormField
             ]
           })
export class InuInputTextView {

  userModel                     = signal<UserForm>({
                                                     uid      : '',
                                                     firstName: '',
                                                     lastName : '',
                                                     email    : '',
                                                     old      : 0
                                                   });
  userForm: FieldTree<UserForm> = form(this.userModel, (path) => {
    required(path.email);
  });

  constructor() {
    InuFormsUtils.onChanged(this.userModel)
      .subscribe(value => {
        this.onChanged(value)
      });
  }

  private onChanged(value: UserForm) {
    //... implementation
  }


const status = InuFormsUtils.isValid(this.userForm);
if (!status.valid) {
  console.warn('The following fields are invalid:', status.invalidFields);
}


export interface ValidityChanges {
  valid: boolean;
  invalidFields: InvalidField[];
}

export interface InvalidField {
  field: string;
  dirty: boolean;
  disabled: boolean;
  touched: boolean;
  errors: any[];
}
